INSERT INTO highlights (id, episode_id, episode_key, start_time, end_time, type, emotion, intensity, confidence, summary, suggestions, status, model_source, model_reason, trigger_score, effect_config, raw_payload, imported_at, updated_at) VALUES ('hl_import_1779779571029_1', 'ep_42f32b2bba95ccc6', '北派寻宝笔记/第66集.mp4', 99, 115, '悬念', 'fear', 0.7, 0.9, '把头用对讲机和留守的孙老大暗语对接，确认周边无外人后，正式下令用“金针灌顶”手法开始打盗洞。', '["金针灌顶是什么手法？","周边真的安全吗？"]', 'published', 'Doubao-Seed-2.0-lite', '深夜密林里通过对讲机传出的盗墓黑话完全贴合隐秘行动设定，未知的操作带来强烈的未知恐惧感。', NULL, NULL, '{"id":"hl_import_1779779571029_1","episodeKey":"北派寻宝笔记/第66集.mp4","startTime":99,"endTime":115,"type":"悬念","emotion":"fear","intensity":0.7,"confidence":0.9,"summary":"把头用对讲机和留守的孙老大暗语对接，确认周边无外人后，正式下令用“金针灌顶”手法开始打盗洞。","suggestions":["金针灌顶是什么手法？","周边真的安全吗？"],"status":"published","modelSource":"Doubao-Seed-2.0-lite","modelReason":"深夜密林里通过对讲机传出的盗墓黑话完全贴合隐秘行动设定，未知的操作带来强烈的未知恐惧感。","importedAt":"2026-05-26T07:12:51.029Z","updatedAt":"2026-06-02T10:08:03.600Z"}', '2026-05-26 07:12:51.029', '2026-06-02 10:08:03.600') ON DUPLICATE KEY UPDATE episode_id=VALUES(episode_id), episode_key=VALUES(episode_key), start_time=VALUES(start_time), end_time=VALUES(end_time), type=VALUES(type), emotion=VALUES(emotion), intensity=VALUES(intensity), confidence=VALUES(confidence), summary=VALUES(summary), suggestions=VALUES(suggestions), status=VALUES(status), model_source=VALUES(model_source), model_reason=VALUES(model_reason), trigger_score=VALUES(trigger_score), effect_config=VALUES(effect_config), raw_payload=VALUES(raw_payload), imported_at=VALUES(imported_at), updated_at=VALUES(updated_at);
INSERT INTO highlights (id, episode_id, episode_key, start_time, end_time, type, emotion, intensity, confidence, summary, suggestions, status, model_source, model_reason, trigger_score, effect_config, raw_payload, imported_at, updated_at) VALUES ('hl_import_1779779571029_2', 'ep_42f32b2bba95ccc6', '北派寻宝笔记/第66集.mp4', 125, 138, '爽点', 'joy', 0.8, 0.9, '孙老二挥动洛阳铲带出带有特殊标记的泥土，精准确认古墓位置，三人立刻兴奋联手加速开挖。', '["这泥土有什么特殊含义？","马上就能挖到墓口了？"]', 'published', 'Doubao-Seed-2.0-lite', '众人辛苦定位终于得到验证，团伙成员兴奋的表情和急促的挖土动作直接释放寻墓成功的爽感。', NULL, NULL, '{"id":"hl_import_1779779571029_2","episodeKey":"北派寻宝笔记/第66集.mp4","startTime":125,"endTime":138,"type":"爽点","emotion":"joy","intensity":0.8,"confidence":0.9,"summary":"孙老二挥动洛阳铲带出带有特殊标记的泥土，精准确认古墓位置，三人立刻兴奋联手加速开挖。","suggestions":["这泥土有什么特殊含义？","马上就能挖到墓口了？"],"status":"published","modelSource":"Doubao-Seed-2.0-lite","modelReason":"众人辛苦定位终于得到验证，团伙成员兴奋的表情和急促的挖土动作直接释放寻墓成功的爽感。","importedAt":"2026-05-26T07:12:51.029Z","updatedAt":"2026-06-02T10:08:03.600Z"}', '2026-05-26 07:12:51.029', '2026-06-02 10:08:03.600') ON DUPLICATE KEY UPDATE episode_id=VALUES(episode_id), episode_key=VALUES(episode_key), start_time=VALUES(start_time), end_time=VALUES(end_time), type=VALUES(type), emotion=VALUES(emotion), intensity=VALUES(intensity), confidence=VALUES(confidence), summary=VALUES(summary), suggestions=VALUES(suggestions), status=VALUES(status), model_source=VALUES(model_source), model_reason=VALUES(model_reason), trigger_score=VALUES(trigger_score), effect_config=VALUES(effect_config), raw_payload=VALUES(raw_payload), imported_at=VALUES(imported_at), updated_at=VALUES(updated_at);
INSERT INTO highlights (id, episode_id, episode_key, start_time, end_time, type, emotion, intensity, confidence, summary, suggestions, status, model_source, model_reason, trigger_score, effect_config, raw_payload, imported_at, updated_at) VALUES ('hl_import_1779779571029_3', 'ep_42f32b2bba95ccc6', '北派寻宝笔记/第66集.mp4', 153, 162, '悬念', 'fear', 0.8, 0.9, '林间传来报丧鸟诡异的鸣叫声，把头脸色大变当场直呼太不吉利，现场压抑感瞬间暴涨。', '["报丧鸟是凶兆吗？","他们会取消行动吗？"]', 'published', 'Doubao-Seed-2.0-lite', '惊悚的怪鸟音效搭配角色凝重紧绷的表情，在深夜盗墓的场景设定下把恐怖不安的氛围拉满。', NULL, NULL, '{"id":"hl_import_1779779571029_3","episodeKey":"北派寻宝笔记/第66集.mp4","startTime":153,"endTime":162,"type":"悬念","emotion":"fear","intensity":0.8,"confidence":0.9,"summary":"林间传来报丧鸟诡异的鸣叫声，把头脸色大变当场直呼太不吉利，现场压抑感瞬间暴涨。","suggestions":["报丧鸟是凶兆吗？","他们会取消行动吗？"],"status":"published","modelSource":"Doubao-Seed-2.0-lite","modelReason":"惊悚的怪鸟音效搭配角色凝重紧绷的表情，在深夜盗墓的场景设定下把恐怖不安的氛围拉满。","importedAt":"2026-05-26T07:12:51.029Z","updatedAt":"2026-06-02T10:08:03.600Z"}', '2026-05-26 07:12:51.029', '2026-06-02 10:08:03.600') ON DUPLICATE KEY UPDATE episode_id=VALUES(episode_id), episode_key=VALUES(episode_key), start_time=VALUES(start_time), end_time=VALUES(end_time), type=VALUES(type), emotion=VALUES(emotion), intensity=VALUES(intensity), confidence=VALUES(confidence), summary=VALUES(summary), suggestions=VALUES(suggestions), status=VALUES(status), model_source=VALUES(model_source), model_reason=VALUES(model_reason), trigger_score=VALUES(trigger_score), effect_config=VALUES(effect_config), raw_payload=VALUES(raw_payload), imported_at=VALUES(imported_at), updated_at=VALUES(updated_at);
