INSERT INTO video_branches (id, episode_id, episode_key, title, setup, interaction_nodes, status, model_source, raw_model_output, created_at, updated_at) VALUES ('vbranch_8d8bcbb5b6f3006e', 'ep_42f32b2bba95ccc6', '北派寻宝笔记/第66集.mp4', '北派寻宝笔记第66集互动分支集', '选取三处关键剧情抉择点，让观众自主决定寻宝小队行动走向，强化沉浸代入爽感', '[{"node_id":"node_1","trigger_highlight_id":"hl_import_1779779571029_0","trigger_time":63,"trigger_description":"把头王显生当众宣布凌晨立刻上山下墓，作为核心队员的你要做出什么选择？","video_branches":[{"branch_id":"follow_order","title":"立刻整备连夜出发","description":"全员当即清点装备连夜上山，抢先一步避开守墓人巡逻，行动丝毫不拖泥带水爽感拉满","duration":15,"user_choice_label":"立刻服从出发","emotion_curve":["紧张","果决","爽感"],"video_prompt":"昏暗农家院会议室里，全员利落地起身收拾洛阳铲、防毒面具等装备，镜头快速扫过每个人紧绷又兴奋的脸，屋外闪电划过，结尾闪过山间零星手电光的远景，氛围紧张刺激","risk_note":"无"},{"branch_id":"delay_action","title":"提议延后一天行动","description":"你当众提出延后行动避开山里暴雨预警，提前打消队伍遇山洪的隐患，凸显你智囊属性","duration":13,"user_choice_label":"要求推迟行动","emotion_curve":["疑惑","冲突","安心"],"video_prompt":"你起身抬手阻止要动身的众人，把天气预报截图拍在桌上，王显生皱眉思索后点头应允，窗外隐约传来远处山风呼啸声，结尾给到墙上暴雨红色预警通知特写，氛围凝重","risk_note":"无"}]},{"node_id":"node_2","trigger_highlight_id":"hl_import_1779779571029_2","trigger_time":132,"trigger_description":"孙老二挥动洛阳铲精准确认古墓位置，接下来你选择什么行动？","video_branches":[{"branch_id":"dig_fast","title":"联手全力快速开挖","description":"众人合力加急掏盗洞，不到十分钟就挖到墓门封石，近在眼前的宝物直接暴露在眼前，爽感十足","duration":12,"user_choice_label":"全力快速开挖","emotion_curve":["兴奋","急促","期待"],"video_prompt":"山林隐蔽土坡旁，四个人轮流挥铲快速挖土尘土飞溅，下一秒洛阳铲哐当磕到青石板，所有人俯身去擦封石上的古老云纹，镜头怼近带纹路的墓门，全员情绪亢奋","risk_note":"无"},{"branch_id":"lay_trap","title":"先布置外围警戒陷阱","description":"你提出先在周边布置预警机关，刚好抓到跟踪而来的敌对盗墓团伙，反杀夺宝占尽先机","duration":14,"user_choice_label":"先布防设陷阱","emotion_curve":["警惕","悬念","爽点"],"video_prompt":"你招呼众人停下挖土，在周边灌木丛牵好细铁丝挂铜铃做预警装置，远处树影后闪过戴鸭舌帽的陌生人身影，镜头定格在晃响的铜铃上，氛围暗藏杀机","risk_note":"无"}]},{"node_id":"node_3","trigger_highlight_id":"hl_import_1779801936106_5","trigger_time":203,"trigger_description":"手电照亮向深处无限延伸的传说龙穴甬道，你第一步要做出什么选择？","video_branches":[{"branch_id":"rush_in","title":"直接举灯冲进甬道","description":"你一马当先打头阵冲进龙穴，率先捡到甬道旁散落的第一件西周金器，直接拿头彩爽爆","duration":11,"user_choice_label":"率先冲进龙穴","emotion_curve":["震撼","冲动","爽点"],"video_prompt":"幽暗漫无边际的汉白玉甬道里，你举着强光手电快步往前冲，脚边地面躺着鎏金铜兽配饰，你弯腰一把抓在手里，镜头给到你手里泛着金光的器物特写，悬念拉满","risk_note":"无"},{"branch_id":"check_trap","title":"先停下排查甬道机关","description":"你拦住全队先排查机关，扔出的石头刚好触发第一排致命暗弩，直接救下全队性命凸显老炮属性","duration":13,"user_choice_label":"先排查机关","emotion_curve":["冷静","惊险","后怕"],"video_prompt":"你伸手猛地拦住要迈步往前走的众人，扔出一块石头到甬道地面，十几支冷箭瞬间从两侧墙壁嗖嗖射出钉在对面墙上，所有人瞬间脸色煞白，镜头给到箭尾羽毛特写，氛围极度惊险","risk_note":"无"}]}]', 'published', 'Doubao-Seed-2.0-lite', '{"title":"北派寻宝笔记第66集互动分支集","setup":"选取三处关键剧情抉择点，让观众自主决定寻宝小队行动走向，强化沉浸代入爽感","interaction_nodes":[{"node_id":"node_1","trigger_highlight_id":"hl_import_1779779571029_0","trigger_time":63,"trigger_description":"把头王显生当众宣布凌晨立刻上山下墓，作为核心队员的你要做出什么选择？","video_branches":[{"branch_id":"follow_order","title":"立刻整备连夜出发","description":"全员当即清点装备连夜上山，抢先一步避开守墓人巡逻，行动丝毫不拖泥带水爽感拉满","duration":15,"user_choice_label":"立刻服从出发","emotion_curve":["紧张","果决","爽感"],"video_prompt":"昏暗农家院会议室里，全员利落地起身收拾洛阳铲、防毒面具等装备，镜头快速扫过每个人紧绷又兴奋的脸，屋外闪电划过，结尾闪过山间零星手电光的远景，氛围紧张刺激","risk_note":"无"},{"branch_id":"delay_action","title":"提议延后一天行动","description":"你当众提出延后行动避开山里暴雨预警，提前打消队伍遇山洪的隐患，凸显你智囊属性","duration":13,"user_choice_label":"要求推迟行动","emotion_curve":["疑惑","冲突","安心"],"video_prompt":"你起身抬手阻止要动身的众人，把天气预报截图拍在桌上，王显生皱眉思索后点头应允，窗外隐约传来远处山风呼啸声，结尾给到墙上暴雨红色预警通知特写，氛围凝重","risk_note":"无"}]},{"node_id":"node_2","trigger_highlight_id":"hl_import_1779779571029_2","trigger_time":132,"trigger_description":"孙老二挥动洛阳铲精准确认古墓位置，接下来你选择什么行动？","video_branches":[{"branch_id":"dig_fast","title":"联手全力快速开挖","description":"众人合力加急掏盗洞，不到十分钟就挖到墓门封石，近在眼前的宝物直接暴露在眼前，爽感十足","duration":12,"user_choice_label":"全力快速开挖","emotion_curve":["兴奋","急促","期待"],"video_prompt":"山林隐蔽土坡旁，四个人轮流挥铲快速挖土尘土飞溅，下一秒洛阳铲哐当磕到青石板，所有人俯身去擦封石上的古老云纹，镜头怼近带纹路的墓门，全员情绪亢奋","risk_note":"无"},{"branch_id":"lay_trap","title":"先布置外围警戒陷阱","description":"你提出先在周边布置预警机关，刚好抓到跟踪而来的敌对盗墓团伙，反杀夺宝占尽先机","duration":14,"user_choice_label":"先布防设陷阱","emotion_curve":["警惕","悬念","爽点"],"