INSERT INTO video_branches (id, episode_id, episode_key, title, setup, interaction_nodes, status, model_source, raw_model_output, created_at, updated_at) VALUES ('vbranch_89ff3142c6a10c62', 'ep_9a263da2ad1e4cec', '北派寻宝笔记/第63集.mp4', '北派寻宝笔记第63集互动分支', '选取全片4个高情绪张力抉择点，匹配爽点悬念互动，不改动原核心设定', '[{"node_id":"node_1","trigger_highlight_id":"hl_bp_63_01","trigger_time":22,"trigger_description":"你被一众追兵围堵在古墓入口，对方手持兵器步步紧逼，该做出什么选择？","video_branches":[{"branch_id":"branch_1_1","title":"直接硬刚反杀","description":"直接亮出袖中秘宝，几招就把围堵的追兵全部放倒，爽感拉满","duration":12,"user_choice_label":"直接出手反杀","emotion_curve":["压迫","爆发","爽点"],"video_prompt":"昏暗古墓入口处，男主攥紧掌心青铜罗盘闪身出招，围堵的追兵接连倒地，手持兵器愣在原地，手持罗盘特写定格，镜头快速推近罗盘上闪现金光的神秘纹路，情绪是利落酣畅，结尾钩子是罗盘纹路突然自主转动","risk_note":"无"},{"branch_id":"branch_1_2","title":"假意投降反戈","description":"假装举手投降，趁对方放松警惕扔出烟雾弹，转头就钻进墓道密道","duration":10,"user_choice_label":"诈降后溜之大吉","emotion_curve":["紧张","出其不意","悬念"],"video_prompt":"古墓入口青石板地面，男主假装举手交出背包，突然掏出烟幕弹扔向地面，白色烟雾瞬间弥漫，男主身影迅速钻进侧边暗门，镜头停在暗门缓缓闭合的缝隙上，情绪是惊险刺激，结尾钩子是追兵首领的刀突然劈到暗门边缘","risk_note":"无"},{"branch_id":"branch_1_3","title":"动用暗号求援","description":"你吹起只有门派弟子能识别的求援暗号，埋伏在附近的同门立刻现身接应","duration":11,"user_choice_label":"吹暗号喊救兵","emotion_curve":["紧张","安心","反转"],"video_prompt":"古墓入口密林边，男主抬手放到嘴边吹起短哨，树后立刻跳出数名持短刃的青衣同门，和追兵形成对峙局面，镜头扫过周围从树后现身的同门，情绪是张力拉满，结尾钩子是领头同门比出一个意料之外的奇怪手势","risk_note":"无"}]},{"node_id":"node_2","trigger_highlight_id":"hl_import_1779780876923_1","trigger_time":40,"trigger_description":"皇帝当众痛骂纨绔后辈无用，要求选出人对战蛮夷比武招亲，你作为苏羽就在殿上该怎么选？","video_branches":[{"branch_id":"branch_2_1","title":"当场主动请缨","description":"直接站出来接下比武招亲的任务，满朝文武全都当场惊呆","duration":13,"user_choice_label":"主动接下比武任务","emotion_curve":["压抑","震惊","爽点"],"video_prompt":"金碧辉煌的金銮殿上，醉醺醺的苏羽晃着步子从队列里站出，对着台阶上的皇帝拱手请战，满朝文武纷纷转头侧目看他，皇帝面露错愕神色，暖黄殿光落在苏羽扬起的脸上，情绪是意外热血，结尾钩子是蛮夷使者在殿下突然露出阴笑","risk_note":"无"},{"branch_id":"branch_2_2","title":"亮隐藏身份打脸","description":"直接亮出你隐姓埋名的寻宝掌事身份，在场所有人瞬间噤声","duration":12,"user_choice_label":"亮出隐藏身份","emotion_curve":["嘲讽","反转","震撼"],"video_prompt":"金銮殿上苏羽从怀中掏出刻有北派寻宝联盟印记的纯铁腰牌，抬手举过头顶，刚才还在嘲讽他的几个官员瞬间僵住，镜头特写腰牌上的雕刻纹路，情绪是强势打脸，结尾钩子是皇帝看到腰牌后突然起身走下台阶","risk_note":"无"}]},{"node_id":"node_3","trigger_highlight_id":"hl_bp_63_02","trigger_time":48,"trigger_description":"你刚拿出扭转局势的关键证据，对面反派还想狡辩，接下来选什么走向？","video_branches":[{"branch_id":"branch_3_1","title":"当场锤死反派","description":"直接把所有证据全部甩出来，把反派所有罪证当众念完，直接送他下狱","duration":11,"user_choice_label":"直接锤死反派","emotion_curve":["对峙","爆发","爽点"],"video_prompt":"公堂之上男主把一叠账册甩到反派脸上，手指账册逐页指认罪证，反派脸色从苍白变成死灰，两侧衙役上前按住他的肩膀，冷白光打在男主坚毅的侧脸上，情绪是大快人心，结尾钩子是反派突然咬向嘴里暗藏的毒囊","risk_note":"无"},{"branch_id":"branch_3_2","title":"留活口钓大鱼","description":"故意留一手不把所有证据亮完，放反派回去顺藤摸瓜挖出背后更大的幕后主使","duration":10,"user_choice_label":"放长线钓大鱼","emotion_curve":["僵持","算计","悬念"],"video_prompt":"公堂上男主故意假装证据不足皱起眉头，挥手示意衙役把还没定罪的反派暂时放回家，反派带着劫后余生的表情快步离开，男主站在门口盯着他的背影，抬手示意下属悄悄尾随，情绪是运筹帷幄，结尾钩子是远处树后有个黑影正在盯着他们","risk_note":"无"}]},{"node_id":"node_4","trigger_highlight_id":"hl_import_1779780876923_3","trigger_time":72,"trigger_description":"皇帝派来的绝顶高手正在房门外准备测试你这个废柴纨绔，此时你还在酒池肉林里享乐，该怎么选？","video_branches":[{"branch_id":"branch_4_1","title":"装醉蒙混过关","description":"直接抱着酒坛子往地上一瘫，装成烂醉不省人事的纨绔傻子，高手完全看不出破绽","duration":9,"user_choice_label":"装醉躲测试","emotion_curve":["惊险","搞笑","爽点"],"video_prompt":"烛火摇曳的奢华卧房里，苏羽抱着酒坛子瘫在美人腿上呼呼大睡，暗中站在梁上的高手盯着他看了半天，最后悄无声息转身跳出窗外，暖红烛光照在苏羽偷偷眯起的眼睛上，情绪是诙谐惊险，结尾钩子是苏羽睁开眼从怀里掏出半块古墓地图","risk_note":"无"},{"branch_id":"branch_4_2","title":"瞬间亮武功吓退高手","description":"你指尖弹出一枚花生米精准打落高手藏在房梁上的飞剑，瞬间展露绝世功夫","duration":10,"user_choice_label":"露一手吓退高手","emotion_curve":["放松","意外","爽点"],"video_prompt":"奢华卧房内苏羽指尖夹着一粒花生米，抬手对着房梁弹出，精准打落高手藏在袖中的短剑，高手身形一震立刻从梁上跳下来拱手行礼，烛光闪过苏羽淡然的侧脸，情绪是实力碾压，结尾钩子是高手递给他一封封有皇帝私印的密信","risk_note":"无"}]}]', 'published', 'Doubao-Seed-2.0-lite', '{"title":"北派寻宝笔记第63集互动分支","setup":"选取全片4个高情绪张力抉择点，匹配爽点悬念互动，不改动原核心设定","interaction_nodes":[{"node_id":"node_1","trigger_highlight_id":"hl_bp_63_01","trigger_time":22,"trigger_description":"你被一众追兵围堵在古墓入口，对方手持兵器步步紧逼，该做出什么选择？","video_branches":[{"branch_id":"branch_1_1","title":"直接硬刚反杀","description":"直接亮出袖中秘宝，几招就把