INSERT INTO video_branches (id, episode_id, episode_key, title, setup, interaction_nodes, status, model_source, raw_model_output, created_at, updated_at) VALUES ('vbranch_f414253d3f72bbb8', 'ep_42f32b2bba95ccc6', '北派寻宝笔记/第66集.mp4', '北派寻宝笔记第66集互动分支', '选取本集两处高张力节点设置互动，强化观众代入感，放大爽点悬念', '[{"node_id":"node_1","trigger_highlight_id":"hl_import_1779779571029_0","trigger_time":63,"trigger_description":"把头突然下令即刻凌晨上山下墓，你要做出什么选择？","video_branches":[{"branch_id":"obey_immediately","title":"立刻服从整装出发","description":"全队全员即刻动身摸黑上山，赶在吉时前顺利摸到古墓入口，寻宝氛围感拉满","duration":13,"user_choice_label":"服从指令立刻出发","emotion_curve":["紧绷","期待","爽感"],"video_prompt":"昏暗土窑内，全队成员瞬间起身快速收拾背包检查探墓装备，镜头扫过每个人凝重又兴奋的脸，暖黄煤油灯晃动，窑门被推开露出山夜黑幕","risk_note":"无"},{"branch_id":"query_decision","title":"当场质疑延后行动","description":"你当众指出准备不足风险过高，和把头激烈争执，揪出队伍内鬼的悬念瞬间拉满","duration":15,"user_choice_label":"提出异议暂缓下墓","emotion_curve":["错愕","对峙","悬疑"],"video_prompt":"土窑内你猛地拍桌站起盯着王显生大声质疑，周围队员纷纷侧目，镜头给到王显生神色陡然阴沉，角落里有人悄悄攥紧匕首露出刀尖，画面定格在对峙瞬间","risk_note":"无"},{"branch_id":"prepare_safeguard","title":"私藏后手留保命符","description":"你悄悄把祖传的辟邪寻宝法器塞进口袋，后续触发别人看不到的隐藏机关预警金手指","duration":11,"user_choice_label":"偷偷多带保命装备","emotion_curve":["隐秘","安心","伏笔"],"video_prompt":"土窑阴影里你背对众人，快速把怀里的黄铜摸金符塞到贴身衣袋，指尖碰到符身的温热纹路，镜头特写符上刻的隐纹微微反光","risk_note":"无"}]},{"node_id":"node_2","trigger_highlight_id":"hl_import_1780399721333_5","trigger_time":203,"trigger_description":"眼前就是传说中的龙穴纵深甬道，你接下来要怎么行动？","video_branches":[{"branch_id":"go_ahead_first","title":"打头阵直闯深处","description":"你举着手电走在最前面开路，率先撞见龙穴里守墓的罕见千年明器，抢先一步捡到宝","duration":14,"user_choice_label":"直接往甬道深处走","emotion_curve":["震撼","亢奋","爽点"],"video_prompt":"幽暗巨型石砌甬道里你举着手电大步走在最前，光柱扫过前方地面露出半块泛着光泽的金缕玉衣碎片，镜头特写金片冷冽反光","risk_note":"无"},{"branch_id":"check_trap_first","title":"先排查入口机关","description":"你谨慎蹲下身查探甬道入口的地砖，刚好触发被前人掩盖的致命毒箭机关，救下全队性命","duration":16,"user_choice_label":"先查入口机关","emotion_curve":["警惕","惊险","爽感"],"video_prompt":"你蹲在甬道入口用洛阳铲敲了敲脚下地砖，察觉异响立刻抬手喊停众人，数支毒箭从墙面缝隙激射而出擦着众人头顶飞过","risk_note":"无"},{"branch_id":"back_for_sup